#!/usr/bin/env python3 """ Spec Validation Skill - automatic validation of PM Agent outputs Usage: python validate.py PLAN-001 python validate.py PLAN-001 --auto-fix python validate.py --all """ import json import re import sys from pathlib import Path from typing import Dict, List, Tuple from dataclasses import dataclass, field from datetime import datetime @dataclass class ValidationResult: """validation result""" passed: bool errors: List[str] = field(default_factory=list) warnings: List[str] = field(default_factory=list) auto_fixes: List[str] = field(default_factory=list) details: Dict = field(default_factory=dict) class SpecValidator: """specification validator""" def __init__(self, project_root: Path, ticket_num: str): self.project_root = project_root self.ticket_num = ticket_num self.rules = self._load_rules() self.project_meta = self._load_project_meta() self.project_type = self.project_meta.get("project_type", "web-fullstack") def _load_rules(self) -> dict: """rules.json load""" rules_path = Path(__file__).parent / "rules.json" with open(rules_path, 'r', encoding='utf-8') as f: return json.load(f) def _load_project_meta(self) -> dict: """project meta info load""" meta_path = self.project_root / ".project-meta.json" if not meta_path.exists(): return {"project_type": "web-fullstack"} with open(meta_path, 'r', encoding='utf-8') as f: return json.load(f) def validate(self, auto_fix: bool = False) -> ValidationResult: """all validation execute""" result = ValidationResult(passed=True) print(f"\n{'='*60}") print(f"Spec Validation: {self.ticket_num}") print(f"project type: {self.project_type}") print(f"{'='*60}\n") # 1. completeness 검사 if self.rules["rules"]["completeness"]["enabled"]: self._check_completeness(result) # 2. scope compliance check if self.rules["rules"]["scope_compliance"]["enabled"]: self._check_scope_compliance(result) # 3. quality 게트 self._check_quality_gates(result) # 4. implementation 세부사항 침범 if self.rules["rules"]["implementation_details"]["enabled"]: self._check_implementation_details(result) # 5. auto fix if auto_fix and self.rules["auto_fix"]["enabled"]: self._apply_auto_fixes(result) # final 판정 result.passed = len(result.errors) == 0 return result def _check_completeness(self, result: ValidationResult): """completeness 검사 - required file and section""" print("1️⃣ completeness 검사...") type_reqs = self.rules["project_type_requirements"].get(self.project_type, {}) required_files = type_reqs.get("required_files", []) # ticket filein slug 추출 ticket_slug = self._extract_ticket_slug() missing_files = [] found_files = [] for file_pattern in required_files: # {number}, {slug} 치환 file_path = file_pattern.replace("{number}", self.ticket_num.replace("PLAN-", "")) file_path = file_path.replace("{slug}", ticket_slug) full_path = self.project_root / "planning" / file_path if full_path.exists(): found_files.append(file_path) # section 검사 self._check_file_sections(full_path, file_path, result) else: missing_files.append(file_path) result.details["completeness"] = {"found": found_files, "missing": missing_files } if missing_files: for file in missing_files: result.errors.append(f"[completeness] required file 누락: {file}") print(f" ❌ {len(missing_files)}items file 누락") else: print(f" ✅ {len(found_files)}/{len(required_files)} file create completed") def _check_file_sections(self, file_path: Path, file_name: str, result: ValidationResult): """file 내 required section check""" type_reqs = self.rules["project_type_requirements"].get(self.project_type, {}) required_sections = type_reqs.get("required_sections", {}) # file type 추출 (backend, frontend, command-spec 등) file_type = None if "backend" in file_name: file_type = "backend" elif "frontend" in file_name: file_type = "frontend" elif "command-spec" in file_name: file_type = "command-spec" elif "screens" in file_name: file_type = "screens" elif "state" in file_name: file_type = "state" elif "api" in file_name: file_type = "api" elif "examples" in file_name: file_type = "examples" if not file_type or file_type not in required_sections: return content = file_path.read_text(encoding='utf-8') missing_sections = [] for section in required_sections[file_type]: # section 헤더 찾기 (## 또 ###) pattern = rf"#+\s*{re.escape(section)}" if not re.search(pattern, content, re.IGNORECASE): missing_sections.append(section) if missing_sections: for section in missing_sections: result.errors.append(f"[completeness] {file_name}to '{section}' section 누락") def _check_scope_compliance(self, result: ValidationResult): """scope compliance check - Gotcha #1""" print("2️⃣ scope compliance check...") # ticket file read ticket_content = self._read_ticket_file() if not ticket_content: result.warnings.append("[range] ticket file 읽 수 없어 range 검사 omit") return # Acceptance Criteria 추출 ticket_features = self._extract_acceptance_criteria(ticket_content) # specification file들 read spec_files = self._find_spec_files() scope_creep_detected = [] scope_keywords = self.rules["rules"]["scope_compliance"]["scope_creep_keywords"] for spec_file in spec_files: content = spec_file.read_text(encoding='utf-8') # range zoom in 키워드 탐지 for keyword in scope_keywords: if keyword in content and keyword not in ticket_content: scope_creep_detected.append((keyword, spec_file.name)) result.details["scope_compliance"] = {"ticket_features": ticket_features, "scope_creep": scope_creep_detected } if scope_creep_detected: # Out-of-Scope section check has_out_of_scope = any("Out of Scope" in f.read_text(encoding='utf-8') or "Out-of-Scope" in f.read_text(encoding='utf-8') for f in spec_files) for keyword, file_name in scope_creep_detected: if has_out_of_scope: result.warnings.append(f"[range] '{keyword}' found (ticketto none) - {file_name}") else: result.errors.append(f"[range] '{keyword}' found (ticketto none) + Out-of-Scope section 누락 - {file_name}") print(f" ⚠️ {len(scope_creep_detected)}items range zoom in of심 키워드 found") else: print(" ✅ range zoom in none") def _check_quality_gates(self, result: ValidationResult): """quality 게트 검사""" print("3️⃣ quality 게트...") quality_rules = self.rules["rules"]["quality_gates"] # API error response 검사 if quality_rules["error_responses"]["enabled"]: self._check_error_responses(result) # HTML 외부 library 검사 if quality_rules["html_libraries"]["enabled"]: self._check_html_libraries(result) # HTML API call 검사 if quality_rules["html_api_calls"]["enabled"]: self._check_html_api_calls(result) # 접근성 test 검사 if quality_rules["accessibility"]["enabled"]: if self.project_type in quality_rules["accessibility"]["applies_to"]: self._check_accessibility(result) # CLI Exit Code 검사 if quality_rules["cli_exit_codes"]["enabled"]: if self.project_type in quality_rules["cli_exit_codes"]["applies_to"]: self._check_cli_exit_codes(result) def _check_error_responses(self, result: ValidationResult): """API error response 검사 - Gotcha #8""" required_codes = self.rules["rules"]["quality_gates"]["error_responses"]["required_codes"] # backend specification 찾기 backend_files = list(self.project_root.glob(f"planning/specs/backend/{self.ticket_num}*.md")) if not backend_files: return missing_errors = [] for backend_file in backend_files: content = backend_file.read_text(encoding='utf-8') for code in required_codes: # "Response 400", "401:", "error 500" 등 pattern pattern = rf"(Response|response|error|Error)\s*{code}" if not re.search(pattern, content, re.IGNORECASE): missing_errors.append(f"{code} (in {backend_file.name})") if missing_errors: for err in missing_errors: result.errors.append(f"[quality] API error response 누락: {err}") print(f" ❌ {len(missing_errors)}items error response 누락") else: print(" ✅ API error response 완비") def _check_html_libraries(self, result: ValidationResult): """HTML 외부 library 검사 - Gotcha #4""" forbidden = self.rules["rules"]["quality_gates"]["html_libraries"]["forbidden_patterns"] html_files = list(self.project_root.glob(f"planning/specs/**/{self.ticket_num}*.html")) violations = [] for html_file in html_files: content = html_file.read_text(encoding='utf-8') for pattern in forbidden: if re.search(pattern, content, re.IGNORECASE): violations.append((pattern, html_file.name)) if violations: for pattern, file_name in violations: result.errors.append(f"[quality] HTML 외부 library 사용: '{pattern}' in {file_name}") print(f" ❌ {len(violations)}items 금지 pattern found") elif html_files: print(" ✅ HTML 외부 library none") def _check_html_api_calls(self, result: ValidationResult): """HTML 실제 API call 검사 - Gotcha #5""" forbidden = self.rules["rules"]["quality_gates"]["html_api_calls"]["forbidden_patterns"] html_files = list(self.project_root.glob(f"planning/specs/**/{self.ticket_num}*.html")) violations = [] for html_file in html_files: content = html_file.read_text(encoding='utf-8') for pattern in forbidden: if re.search(pattern, content): violations.append((pattern, html_file.name)) if violations: for pattern, file_name in violations: result.errors.append(f"[quality] HTML 실제 API call 금지: '{pattern}' in {file_name}") print(f" ❌ {len(violations)}items 금지 API call found") elif html_files: print(" ✅ HTML API call none (목업만 사용)") def _check_accessibility(self, result: ValidationResult): """접근성 test 검사 - Gotcha #9""" keywords = self.rules["rules"]["quality_gates"]["accessibility"]["keywords"] test_files = list(self.project_root.glob(f"planning/specs/test-cases/{self.ticket_num}*frontend.md")) if not test_files: return found = False for test_file in test_files: content = test_file.read_text(encoding='utf-8') for keyword in keywords: if keyword in content: found = True break if found: break if not found: result.warnings.append("[quality] 접근성 test case 누락") print(" ⚠️ 접근성 test case 누락") else: print(" ✅ 접근성 test 포함") def _check_cli_exit_codes(self, result: ValidationResult): """CLI Exit Code 검사""" keywords = self.rules["rules"]["quality_gates"]["cli_exit_codes"]["keywords"] spec_files = list(self.project_root.glob(f"planning/specs/{self.ticket_num}*command-spec.md")) if not spec_files: return found = False for spec_file in spec_files: content = spec_file.read_text(encoding='utf-8') for keyword in keywords: if keyword in content: found = True break if found: break if not found: result.errors.append("[quality] CLI Exit Code 정of 누락") print(" ❌ CLI Exit Code 정of 누락") else: print(" ✅ CLI Exit Code 정of됨") def _check_implementation_details(self, result: ValidationResult): """implementation 세부사항 침범 검사 - Gotcha #10""" print("4️⃣ implementation 세부사항 침범 검사...") forbidden = self.rules["rules"]["implementation_details"]["forbidden_keywords"] spec_files = self._find_spec_files() violations = [] for spec_file in spec_files: content = spec_file.read_text(encoding='utf-8') for keyword in forbidden: if keyword in content: violations.append((keyword, spec_file.name)) result.details["implementation_details"] = violations if violations: for keyword, file_name in violations: result.warnings.append(f"[implementation] implementation 세부사항 포함 of심: '{keyword}' in {file_name}") print(f" ⚠️ {len(violations)}items implementation 세부사항 키워드 found") else: print(" ✅ implementation 세부사항 침범 none") def _apply_auto_fixes(self, result: ValidationResult): """auto fix 적용""" print("\n5️⃣ auto fix 적용...") auto_fix_rules = self.rules["auto_fix"]["rules"] for rule in auto_fix_rules: if not rule["enabled"]: continue if rule["id"] == "add_out_of_scope_section": self._add_out_of_scope_section(result) elif rule["id"] == "replace_hardcoded_secrets": self._replace_hardcoded_secrets(result) elif rule["id"] == "http_to_https": self._http_to_https(result) def _add_out_of_scope_section(self, result: ValidationResult): """Out-of-Scope section auto add""" spec_files = self._find_spec_files() for spec_file in spec_files: content = spec_file.read_text(encoding='utf-8') if "Out of Scope" not in content and "Out-of-Scope" not in content: # file endto section add new_content = content.rstrip() + "\n\n## Out of Scope\n\n(specification validation in progress auto create됨 - 검토 after manual write required)\n\n" spec_file.write_text(new_content, encoding='utf-8') result.auto_fixes.append(f"Out-of-Scope section add: {spec_file.name}") def _replace_hardcoded_secrets(self, result: ValidationResult): """하드코딩된 password → environment variable""" patterns = self.rules["auto_fix"]["rules"][1]["patterns"] spec_files = self._find_spec_files() for spec_file in spec_files: content = spec_file.read_text(encoding='utf-8') modified = False for pattern_rule in patterns: old_pattern = pattern_rule["find"] new_pattern = pattern_rule["replace"] if re.search(old_pattern, content): content = re.sub(old_pattern, new_pattern, content) modified = True if modified: spec_file.write_text(content, encoding='utf-8') result.auto_fixes.append(f"하드코딩 password remove: {spec_file.name}") def _http_to_https(self, result: ValidationResult): """HTTP → HTTPS convert""" spec_files = self._find_spec_files() for spec_file in spec_files: content = spec_file.read_text(encoding='utf-8') if "http://" in content: content = content.replace("http://", "https://") spec_file.write_text(content, encoding='utf-8') result.auto_fixes.append(f"HTTP → HTTPS convert: {spec_file.name}") # Helper methods def _extract_ticket_slug(self) -> str: """ticket filein slug 추출""" ticket_files = list(self.project_root.glob(f"planning/tickets/{self.ticket_num}*.md")) if not ticket_files: return "unknown" # PLAN-001-user-auth.md → user-auth filename = ticket_files[0].stem parts = filename.split("-", 2) if len(parts) >= 3: return parts[2] return "unknown" def _read_ticket_file(self) -> str: """ticket file read""" ticket_files = list(self.project_root.glob(f"planning/tickets/{self.ticket_num}*.md")) if not ticket_files: return "" return ticket_files[0].read_text(encoding='utf-8') def _extract_acceptance_criteria(self, ticket_content: str) -> List[str]: """ticketin Acceptance Criteria 추출""" # "## Acceptance Criteria" section 찾기 pattern = r"##\s*Acceptance Criteria\s*\n(.*?)(?=\n##|\Z)" match = re.search(pattern, ticket_content, re.DOTALL | re.IGNORECASE) if not match: return [] criteria_text = match.group(1) # each 항목 추출 (- 또 * to start) items = re.findall(r"^[*-]\s*(.+)$", criteria_text, re.MULTILINE) return items def _find_spec_files(self) -> List[Path]: """specification file들 찾기""" return list(self.project_root.glob(f"planning/specs/**/{self.ticket_num}*.md")) def print_result(self, result: ValidationResult): """result output""" print(f"\n{'='*60}") if result.passed: print(f"✅ Spec Validation passed: {self.ticket_num}") else: print(f"❌ Spec Validation failure: {self.ticket_num}") print(f"{'='*60}\n") # error if result.errors: print(f"error ({len(result.errors)}items):") for i, err in enumerate(result.errors, 1): print(f"{i}. {err}") print() # warning if result.warnings: print(f"warning ({len(result.warnings)}items):") for i, warn in enumerate(result.warnings, 1): print(f"{i}. {warn}") print() # auto fix if result.auto_fixes: print(f"auto fix ({len(result.auto_fixes)}items):") for i, fix in enumerate(result.auto_fixes, 1): print(f"✓ {fix}") print() # next 조치 print("next 조치:") if result.passed: print("Coding Agent execute possible") else: print("1. re-execute PM Agent하여 누락된 file/section create") print("2. error fix after 재validation required") print() def save_log(self, result: ValidationResult): """validation to그 save""" log_dir = self.project_root / "logs" / "validate-spec" log_dir.mkdir(parents=True, exist_ok=True) timestamp = datetime.now().strftime("%Y%m%d-%H%M%S") log_file = log_dir / f"{timestamp}-{self.ticket_num}.md" status = "✅ passed" if result.passed else "❌ failure" log_content = f"""# Spec Validation Log: {self.ticket_num} - **Skill**: validate-spec - **project**: {self.project_root.name} - **ticket**: {self.ticket_num} - **일when**: {datetime.now().strftime("%Y-%m-%d %H:%M:%S")} - **result**: {status} --- ## validation result ### completeness """ if "completeness" in result.details: found = result.details["completeness"]["found"] missing = result.details["completeness"]["missing"] log_content += f"- ✅ {len(found)}/{len(found) + len(missing)} file create completed\n" if missing: log_content += f"- ❌ 누락: {', '.join(missing)}\n" log_content += "\n### range 준수\n" if "scope_compliance" in result.details: scope_creep = result.details["scope_compliance"]["scope_creep"] if scope_creep: log_content += f"- ⚠️ {len(scope_creep)}items range zoom in of심 키워드 found\n" for keyword, file_name in scope_creep: log_content += f" - '{keyword}' in {file_name}\n" else: log_content += "- ✅ range zoom in none\n" log_content += "\n### quality 게트\n" log_content += "- API error response, HTML rule 등 validation completed\n" log_content += "\n### implementation 세부사항\n" if "implementation_details" in result.details: violations = result.details["implementation_details"] if violations: log_content += f"- ⚠️ {len(violations)}items implementation 세부사항 키워드 found\n" else: log_content += "- ✅ 침범 none\n" log_content += "\n---\n\n## issue 상세\n\n" if result.errors: log_content += "### error\n\n" for err in result.errors: log_content += f"- {err}\n" log_content += "\n" if result.warnings: log_content += "### warning\n\n" for warn in result.warnings: log_content += f"- {warn}\n" log_content += "\n" if result.auto_fixes: log_content += "### auto fix\n\n" for fix in result.auto_fixes: log_content += f"- ✓ {fix}\n" log_content += "\n" log_content += "---\n\n## next 조치\n\n" if result.passed: log_content += "Coding Agent execute possible\n" else: log_content += "re-execute PM Agent 또 manual fix required\n" log_file.write_text(log_content, encoding='utf-8') print(f"📝 to그 save: {log_file}") def main(): """메인 execute""" if len(sys.argv) < 2: print("Usage: python validate.py PLAN-001 [--auto-fix]") sys.exit(1) ticket_num = sys.argv[1] auto_fix = "--auto-fix" in sys.argv # project 루트 찾기 (current locationin 상upto navigation) current = Path.cwd() project_root = None # team/scriptsin execute when → project 루트 찾기 while current!= current.parent: if (current / ".project-meta.json").exists() or (current / "planning").exists(): project_root = current break current = current.parent if not project_root: print("❌ project 루트not found (.project-meta.json 또 planning/ directory)") sys.exit(1) # validation execute validator = SpecValidator(project_root, ticket_num) result = validator.validate(auto_fix=auto_fix) # result output validator.print_result(result) validator.save_log(result) # Exit code sys.exit(0 if result.passed else 1) if __name__ == "__main__": main()